const makeIcon = (children: React.ReactElement) =>
	function IconWrapper(props: React.ComponentProps<'svg'>) {
		return (
			<svg
				data-slot='icon'
				viewBox='0 0 24 24'
				width={24}
				height={24}
				fill='currentColor'
				role='img'
				aria-label='icon'
				{...props}
			>
				{children}
			</svg>
		)
	}

